from collections import Counter

def rearrange_characters(s):
    char_count = Counter(s)
    
    max_freq = max(char_count.values())
    
    n = len(s)
    num_to_move = n - max_freq
    
    if num_to_move > (n + 1) // 2:
        return "Not Possible"
    freq_chars = sorted([(count, char) for char, count in char_count.items()], reverse=True)
    
    result = []
    i = 0
    
    while i < n:
        result.append(freq_chars[i][1])
        j = (i + 1) % n
        while freq_chars[j][0] <= 0 or freq_chars[j][1] == result[-1]:
            j = (j + 1) % n
        
        result.append(freq_chars[j][1])
        
        freq_chars[i][0] -= 1
        freq_chars[j][0] -= 1
        
        i += 2
    
    return ''.join(result)

s = "aaabbcc"
print(rearrange_characters(s)) 